solution_code:
#include <iostream>

class A
{
public:
    int m_value{};

    A(int value)
        : m_value{ value }
    {
    }
};

class B : public A
{
public:
    B(int value)
        : A{ value }
    {
    }
};

class C : public A
{
public:
    C(int value)
        : A{ value }
    {
    }
};

class D : public B, public C
{
public:
    D(int bVal, int cVal)
        : B{ bVal }
        , C{ cVal }
    {
    }

    void show() const
    {
        std::cout << "B::value: " << B::m_value << '\n';
        std::cout << "C::value: " << C::m_value << '\n';
        std::cout << "sum: " << B::m_value + C::m_value << '\n';
    }
};

int main()
{
    int bVal{};
    int cVal{};
    std::cin >> bVal >> cVal;

    D d{ bVal, cVal };
    d.show();

    return 0;
}
